import React from 'react';
import { BrowserRouter as Router, Route, Switch } from "react-router-dom"; 
import Layout from './Layout';
import './App.css';
const App=() => { 
  return (
<Router>
  <Layout>
<Switch>
<Route path="/" exact render={() => <h1>Hello world</h1>} /> <Route render={() => <h1>404 Not found</h1>} />
</Switch> </Layout>
</Router>
  );

}




export default App;
